mapper.select:
SELECT af.alarm_feed_id AS alarmFeedId, af.alarm_title AS alarmTitle, af.severity_level AS severityLevel, af.occurred_at AS occurredAt, af.message AS description, af.is_read AS isRead FROM alarm_feed af WHERE 1=1
AND af.instance_id = #{instanceId}
AND af.database_id = #{databaseId}
AND af.severity_level = #{severityLevel}
AND af.is_read = #{isRead}
ORDER BY af.occurred_at DESC LIMIT 100

mapper.update:
UPDATE alarm_feed
SET is_read = TRUE
WHERE alarm_feed_id = #{alarmFeedId}
